import React from 'react';
import { IconProps } from "../types";

type ArrowIconProps = IconProps & {
  direction?: 'right' | 'left' | 'up' | 'down';
};

export const ArrowIcon = ({ direction = 'down', className, size = 24, color = 'currentColor', strokeWidth = 2, ...props }: ArrowIconProps) => {
  const rotation = {
    right: '',
    left: 'rotate-180',
    up: '-rotate-90',
    down: 'rotate-90',
  }[direction];

  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke={color}
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      className={`${rotation} ${className ?? ''}`}
      {...props}
    >
      <line x1="5" y1="12" x2="19" y2="12" />
      <polyline points="12 5 19 12 12 19" fill="none" />
    </svg>
  );
};

export default ArrowIcon
